import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate, Toggle } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('RankScene')
export class RankScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Toggle)
    levelTabToggle: Toggle = null;
    
    @property(Toggle)
    powerTabToggle: Toggle = null;
    
    @property(Toggle)
    wealthTabToggle: Toggle = null;
    
    @property(Toggle)
    meritTabToggle: Toggle = null;
    
    @property(ScrollView)
    rankListScrollView: ScrollView = null;
    
    @property(Node)
    rankItemPrefab: Node = null;
    
    @property(Label)
    myRankLabel: Label = null;
    
    private currentTab: string = 'level';
    
    private rankData = {
        level: [
            { rank: 1, name: '财神本尊', level: 99, value: 99 },
            { rank: 2, name: '金身罗汉', level: 85, value: 85 },
            { rank: 3, name: '铜身道长', level: 72, value: 72 },
            { rank: 4, name: '木骨居士', level: 65, value: 65 },
            { rank: 5, name: '泥胎修士', level: 58, value: 58 }
        ],
        power: [
            { rank: 1, name: '战神', level: 90, value: 99999 },
            { rank: 2, name: '杀神', level: 85, value: 88888 },
            { rank: 3, name: '斗战胜佛', level: 80, value: 77777 }
        ],
        wealth: [
            { rank: 1, name: '首富', level: 70, value: 9999999 },
            { rank: 2, name: '大富翁', level: 65, value: 8888888 },
            { rank: 3, name: '财主', level: 60, value: 7777777 }
        ],
        merit: [
            { rank: 1, name: '功德无量', level: 75, value: 99999 },
            { rank: 2, name: '大善人', level: 70, value: 88888 },
            { rank: 3, name: '行善积德', level: 65, value: 77777 }
        ]
    };
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.levelTabToggle.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('level'), this);
        this.powerTabToggle.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('power'), this);
        this.wealthTabToggle.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('wealth'), this);
        this.meritTabToggle.node.on(Toggle.EventType.TOGGLE, () => this.onTabChange('merit'), this);
    }
    
    start() {
        this.updateRankList();
        this.updateMyRank();
    }
    
    onTabChange(tab: string) {
        this.currentTab = tab;
        this.updateRankList();
    }
    
    updateRankList() {
        const content = this.rankListScrollView.content;
        content.removeAllChildren();
        
        const ranks = this.rankData[this.currentTab] || [];
        
        for (const item of ranks) {
            const node = instantiate(this.rankItemPrefab);
            
            // 排名图标
            let rankIcon = '';
            if (item.rank === 1) rankIcon = '🥇';
            else if (item.rank === 2) rankIcon = '🥈';
            else if (item.rank === 3) rankIcon = '🥉';
            else rankIcon = `${item.rank}`;
            
            node.getChildByName('RankLabel').getComponent(Label).string = rankIcon;
            node.getChildByName('NameLabel').getComponent(Label).string = item.name;
            node.getChildByName('LevelLabel').getComponent(Label).string = `Lv.${item.level}`;
            node.getChildByName('ValueLabel').getComponent(Label).string = this.formatValue(item.value);
            
            content.addChild(node);
        }
    }
    
    updateMyRank() {
        const myLevel = GameManager.getInstance().playerData.getLevel();
        this.myRankLabel.string = `我的等级: ${myLevel} (未上榜)`;
    }
    
    formatValue(value: number): string {
        if (value >= 100000000) return (value / 100000000).toFixed(1) + '亿';
        if (value >= 10000) return (value / 10000).toFixed(1) + '万';
        return value.toString();
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
